class TokenGenerationService {
  private val sessionTokens = new ConcurrentHashMap[String, SessionToken]()
  private val apiKeys = new ConcurrentHashMap[String, ApiKey]()
  private val random = new Random()

  def generateSessionToken(userId: String, ttlSeconds: Long = 3600): SessionToken = {
    val token = random.alphanumeric.take(32).mkString
    val now = Instant.now()
    val expiresAt = now.plusSeconds(ttlSeconds)
    
    val sessionToken = SessionToken(
      token = token,
      userId = userId,
      createdAt = now,
      expiresAt = expiresAt
    )
    
    sessionTokens.put(token, sessionToken)
    sessionToken
  }

  def generateApiKey(name: String): ApiKey = {
    val key = random.alphanumeric.take(32).mkString
    val now = Instant.now()
    
    val apiKey = ApiKey(
      key = key,
      name = name,
      createdAt = now,
      isActive = true
    )
    
    apiKeys.put(key, apiKey)
    apiKey
  }

  def validateSessionToken(token: String): Option[SessionToken] = {
    Option(sessionTokens.get(token)).filter { st =>
      st.expiresAt.isAfter(Instant.now())
    }
  }

  def validateApiKey(key: String): Option[ApiKey] = {
    Option(apiKeys.get(key)).filter(_.isActive)
  }

  def invalidateSessionToken(token: String): Boolean = {
    sessionTokens.remove(token) != null
  }

  def revokeApiKey(key: String): Boolean = {
