class SecureTokenGenerator(seed: Option[Long] = None) {
  private val random = seed.map(new Random(_)).getOrElse(new Random())

  def generateToken(length: Int = 32): String = {
    random.alphanumeric.take(length).mkString
  }

  def generateHexToken(length: Int = 32): String = {
    random.alphanumeric.filter(c => c.isDigit || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F'))
      .take(length)
      .mkString
      .toLowerCase
  }

  def generateNumericToken(length: Int = 6): String = {
    (1 to length).map(_ => random.nextInt(10)).mkString
  }

  def generateCustomToken(charset: String, length: Int): String = {
    (1 to length).map(_ => charset(random.nextInt(charset.length))).mkString
  }
}

class SessionManager {
  private val tokenService = TokenGenerationService()
  private val tokenGenerator = new SecureTokenGenerator()

  def createSession(userId: String, ttlSeconds: Long = 3600): String = {
    val sessionToken = tokenService.generateSessionToken(userId, ttlSeconds)
    sessionToken.token
  }

  def createApiKey(name: String): String = {
    val apiKey = tokenService.generateApiKey(name)
    apiKey.key
  }

  def authenticate(token: String): Option[String] = {
    tokenService.validateSessionToken(token).map(_.userId)
  }

  def authenticateApiKey(key: String): Option[String] = {
    tokenService.validateApiKey(key).map(_.name)
  }

  def logout(token: String): Boolean = {
    tokenService.invalidateSessionToken(token)
  }

  def refreshSession(token: String, ttlSeconds: Long = 3600): Option[String] = {
    tokenService.refreshSessionToken(token, ttlSeconds).map(_.token)
  }

  def revokeApiKey(key: String): Boolean = {
