    tokenService.cleanupExpiredTokens()
  }

  def logoutAllUserSessions(userId: String): Int = {
    tokenService.invalidateUserSessions(userId)
  }

  def generateOneTimeToken(length: Int = 6): String = {
    tokenGenerator.generateNumericToken(length)
  }

  def generatePasswordResetToken(): String = {
    tokenGenerator.generateToken(48)
  }
}

object SessionManager {
  def apply(): SessionManager = new SessionManager()
